#include<bits/stdc++.h>
using namespace std;
long long n,x[100010],a[100010],b[100010];
double dp[100010][2];
double dis(long long u,long long v){
    if(u>=v){
        return (u-v)/1.3;
    }else{
        return (v-u)/0.7;
    }
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>x[i];
    }
    for(int i=1;i<n;i++){
        cin>>a[i]>>b[i+1];
    }
    for(int i=1;i<=n;i++){
        dp[i][1]=min(dp[i-1][0]+dis(0,a[i-1]),dp[i-1][1]+dis(b[i-1],a[i-1]));
        if(i==1){
            dp[i][1]=x[1];
        }
        dp[i][0]=min(dp[i-1][0]+x[i]-x[i-1],dp[i][1]+dis(b[i],0));
    }
    cout<<fixed<<setprecision(2)<<round(dp[n][0]*100.0)/100.0<<'\n';
    return 0;
}
